import {
  ChangeDetectionStrategy,
  Component,
  forwardRef,
  InjectionToken,
  model,
  ViewEncapsulation,
} from '@angular/core';

/**
 * Task — collapsible card with file attachments. Mirrors React `Task`.
 *
 * Owns its open/close state; opens by default like the React version
 * (`defaultOpen=true`).
 */
export interface TaskState {
  isOpen: () => boolean;
  setOpen(open: boolean): void;
  toggle(): void;
}

export const TASK = new InjectionToken<TaskState>('TaskState');

@Component({
  selector: 'task',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ng-content />`,
  host: {
    class: 'block',
  },
  providers: [{ provide: TASK, useExisting: forwardRef(() => Task) }],
})
export class Task implements TaskState {
  readonly open = model<boolean>(true);

  readonly isOpen = () => this.open();

  setOpen(open: boolean): void {
    this.open.set(open);
  }

  toggle(): void {
    this.open.update((v) => !v);
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  ViewEncapsulation,
} from '@angular/core';

import { TASK } from './task';

/**
 * TaskContent — collapsible body for a Task. Mirrors React `TaskContent`.
 */
@Component({
  selector: 'task-content',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    @if (open()) {
      <div
        class="mt-4 space-y-2 border-muted border-l-2 pl-4 text-popover-foreground outline-none animate-in slide-in-from-top-2"
      >
        <ng-content />
      </div>
    }
  `,
})
export class TaskContent {
  private readonly state = inject(TASK);
  protected readonly open = computed(() => this.state.isOpen());
}

import {
  ChangeDetectionStrategy,
  Component,
  ViewEncapsulation,
} from '@angular/core';
import { Badge } from '@gremorie/ng-display';

/**
 * TaskItem — single line in a Task body. Mirrors React `TaskItem`.
 */
@Component({
  selector: 'task-item',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ng-content />`,
  host: {
    class: 'text-muted-foreground text-sm block',
  },
})
export class TaskItem {}

/**
 * TaskItemFile — file chip used inside a TaskItem. Mirrors React
 * `TaskItemFile`.
 *
 * Dogfoods `gr-badge` (variant `secondary`) from `@gremorie/ng-display`.
 */
@Component({
  selector: 'task-item-file',
  standalone: true,
  imports: [Badge],
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <gr-badge variant="secondary" class="rounded-md font-normal">
      <ng-content />
    </gr-badge>
  `,
  host: {
    class: 'inline-flex',
  },
})
export class TaskItemFile {}

export { Task, TASK } from './task';
export type { TaskState } from './task';
export { TaskTrigger } from './task-trigger';
export { TaskContent } from './task-content';
export { TaskItem, TaskItemFile } from './task-item';
